import jwt from 'jsonwebtoken';
import { config } from '../config';

const SECRET = config.JWT_SECRET || 'fallback-dev-secret';

export function validateToken(token: string): { userId: string } | null {
  try {
    const decoded = jwt.verify(token, SECRET) as { userId: string };
    return decoded;
  } catch {
    return null;
  }
}

export function decodeToken(token: string): Record<string, unknown> | null {
  return jwt.decode(token) as Record<string, unknown> | null;
}

export function isTokenExpired(token: string): boolean {
  const decoded = decodeToken(token);
  if (!decoded || !decoded.exp) return true;
  return (decoded.exp as number) < Date.now() / 1000;
}

import { validateToken } from './token-validator';
import { redis } from '../cache';

const SESSION_TTL = 86400; // 24 hours

interface Session {
  userId: string;
  createdAt: number;
  lastActivity: number;
}

export async function createSession(userId: string): Promise<string> {
  const sessionId = crypto.randomUUID();
  const session: Session = { userId, createdAt: Date.now(), lastActivity: Date.now() };
  await redis.set(`session:${sessionId}`, JSON.stringify(session), 'EX', SESSION_TTL);
  return sessionId;
}

export async function getSession(sessionId: string): Promise<Session | null> {
  const data = await redis.get(`session:${sessionId}`);
  if (!data) return null;
  return JSON.parse(data) as Session;
}

export async function refreshSession(sessionId: string): Promise<boolean> {
  const session = await getSession(sessionId);
  if (!session) return false;
  session.lastActivity = Date.now();
  await redis.set(`session:${sessionId}`, JSON.stringify(session), 'EX', SESSION_TTL);
  return true;
}

export async function deleteSession(sessionId: string): Promise<void> {
  await redis.del(`session:${sessionId}`);
}
